// Gugustus - AntiTabComplete.java:
// Cancel outgoing tab complete to hide command exploration
@EventTarget
public void onPacketSend(EventSendPacket event) {
    if (event.getPacket() instanceof C14PacketTabComplete) {
        // Prevent server from seeing what we're tab-completing
        event.setCancelled(true);
    }
}

